WHEN 14 THEN '# useState e Hooks em React

Hooks permitem usar estado e outros recursos do React em componentes funcionais.

## useState

```jsx
import { useState } from ''react'';

function Contador() {
  const [contador, setContador] = useState(0);

  return (
    <div>
      <p>Contador: {contador}</p>
      <button onClick={() => setContador(contador + 1)}>+</button>
      <button onClick={() => setContador(contador - 1)}>-</button>
    </div>
  );
}
```

## Múltiplos Estados

```jsx
function Formulario() {
  const [nome, setNome] = useState('''');
  const [email, setEmail] = useState('''');
  const [idade, setIdade] = useState(0);

  return (
    <form>
      <input value={nome} onChange={(e) => setNome(e.target.value)} />
      <input value={email} onChange={(e) => setEmail(e.target.value)} />
      <input type="number" value={idade} onChange={(e) => setIdade(Number(e.target.value))} />
    </form>
  );
}
```

## Estado com Objetos

```jsx
function Perfil() {
  const [usuario, setUsuario] = useState({
    nome: '''',
    email: '''',
    idade: 0
  });

  const handleChange = (campo, valor) => {
    setUsuario({...usuario, [campo]: valor});
  };
}
```

## Boas Práticas

1. Não modifique o estado diretamente
2. Use funções de atualização para estados baseados no anterior
3. Agrupe estados relacionados em objetos
4. Inicialize estados com valores apropriados'
WHEN 15 THEN '# useEffect e Ciclo de Vida

useEffect permite executar efeitos colaterais em componentes funcionais.

## Sintaxe Básica

```jsx
import { useEffect, useState } from ''react'';

function Exemplo() {
  const [contador, setContador] = useState(0);

  useEffect(() => {
    document.title = `Contador: ${contador}`;
  }, [contador]);

  return <button onClick={() => setContador(contador + 1)}>+</button>;
}
```

## Buscar Dados de API

```jsx
function Usuarios() {
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(''https://api.example.com/usuarios'')
      .then(res => res.json())
      .then(data => {
        setUsuarios(data);
        setLoading(false);
      });
  }, []);

  if (loading) return <p>Carregando...</p>;
  return <ul>{usuarios.map(u => <li key={u.id}>{u.nome}</li>)}</ul>;
}
```

## Cleanup

```jsx
useEffect(() => {
  const interval = setInterval(() => {
    console.log(''Tick'');
  }, 1000);

  return () => clearInterval(interval);
}, []);
```

## Dependências

- `[]` - Executa apenas uma vez (mount)
- `[var]` - Executa quando var mudar
- Sem array - Executa em toda renderização'
WHEN 16 THEN '# Introdução a Bancos de Dados SQL

Bancos de dados relacionais armazenam dados em tabelas com linhas e colunas.

## Conceitos Fundamentais

### Tabelas
```sql
CREATE TABLE usuarios (
  id INT PRIMARY KEY AUTO_INCREMENT,
  nome VARCHAR(100) NOT NULL,
  email VARCHAR(100) UNIQUE NOT NULL,
  senha VARCHAR(255) NOT NULL,
  criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
```

### Tipos de Dados
- **INT**: Números inteiros
- **VARCHAR(n)**: Texto com tamanho máximo
- **TEXT**: Texto longo
- **DATE/DATETIME**: Datas
- **BOOLEAN**: Verdadeiro/Falso
- **DECIMAL(p,s)**: Números decimais

## SELECT - Consultar Dados

```sql
-- Todos os registros
SELECT * FROM usuarios;

-- Colunas específicas
SELECT nome, email FROM usuarios;

-- Com filtro
SELECT * FROM usuarios WHERE idade > 18;

-- Ordenação
SELECT * FROM usuarios ORDER BY nome ASC;

-- Limite
SELECT * FROM usuarios LIMIT 10;
```

## INSERT - Inserir Dados

```sql
INSERT INTO usuarios (nome, email, senha) 
VALUES (''João'', ''joao@email.com'', ''hash123'');
```

## UPDATE - Atualizar Dados

```sql
UPDATE usuarios 
SET nome = ''João Silva'' 
WHERE id = 1;
```

## DELETE - Deletar Dados

```sql
DELETE FROM usuarios WHERE id = 1;
```'
WHEN 17 THEN '# Relacionamentos e JOINs

Relacionamentos conectam tabelas através de chaves estrangeiras.

## Tipos de Relacionamentos

### Um para Muitos (1:N)
```sql
CREATE TABLE posts (
  id INT PRIMARY KEY,
  titulo VARCHAR(200),
  conteudo TEXT,
  usuario_id INT,
  FOREIGN KEY (usuario_id) REFERENCES usuarios(id)
);
```

### Muitos para Muitos (N:N)
```sql
CREATE TABLE cursos (
  id INT PRIMARY KEY,
  nome VARCHAR(100)
);

CREATE TABLE alunos (
  id INT PRIMARY KEY,
  nome VARCHAR(100)
);

CREATE TABLE matriculas (
  aluno_id INT,
  curso_id INT,
  data_matricula DATE,
  PRIMARY KEY (aluno_id, curso_id),
  FOREIGN KEY (aluno_id) REFERENCES alunos(id),
  FOREIGN KEY (curso_id) REFERENCES cursos(id)
);
```

## JOINs

### INNER JOIN
```sql
SELECT posts.titulo, usuarios.nome
FROM posts
INNER JOIN usuarios ON posts.usuario_id = usuarios.id;
```

### LEFT JOIN
```sql
SELECT usuarios.nome, COUNT(posts.id) as total_posts
FROM usuarios
LEFT JOIN posts ON usuarios.id = posts.usuario_id
GROUP BY usuarios.id;
```

## Agregações

```sql
SELECT COUNT(*) FROM usuarios;
SELECT AVG(idade) FROM usuarios;
SELECT MAX(salario) FROM funcionarios;
SELECT MIN(preco) FROM produtos;
SELECT SUM(valor) FROM vendas;
```'
WHEN 18 THEN '# Índices e Otimização

Índices melhoram a performance de consultas.

## Criar Índices

```sql
CREATE INDEX idx_email ON usuarios(email);
CREATE INDEX idx_nome_email ON usuarios(nome, email);
```

## Transações

```sql
START TRANSACTION;

UPDATE contas SET saldo = saldo - 100 WHERE id = 1;
UPDATE contas SET saldo = saldo + 100 WHERE id = 2;

COMMIT;
-- ou ROLLBACK em caso de erro
```

## Boas Práticas

1. Use índices em colunas de busca frequente
2. Evite SELECT * em produção
3. Use LIMIT para grandes resultados
4. Normalize dados para evitar redundância
5. Use prepared statements para segurança

## Exemplo Completo

```sql
-- Buscar usuários com seus posts
SELECT 
  u.nome,
  u.email,
  COUNT(p.id) as total_posts,
  MAX(p.criado_em) as ultimo_post
FROM usuarios u
LEFT JOIN posts p ON u.id = p.usuario_id
WHERE u.ativo = true
GROUP BY u.id
HAVING total_posts > 0
ORDER BY total_posts DESC
LIMIT 10;
```'
